namespace sv_e28233553a9341ab851b6ec0a2969985.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_e28233553a9341ab851b6ec0a2969985.Services

<button class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <span class="channel-description">@TruncatedDescription</span>
</button>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..37] + "..."
            : Channel.Description;
}

.channel-item {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    width: 100%;
    padding: 8px 12px;
    border: none;
    background: transparent;
    cursor: pointer;
    border-radius: 6px;
    text-align: left;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
}

.channel-description {
    font-size: 0.78rem;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 2px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    max-width: 100%;
}

.message-input-container {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    resize: none;
    font-family: inherit;
    font-size: 0.9rem;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #4a90d9;
}

.send-button {
    padding: 8px 20px;
    background-color: #4a90d9;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-button:hover:not(:disabled) {
    background-color: #357abd;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_e28233553a9341ab851b6ec0a2969985.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadInfo is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadInfo.ReplyCount @(ThreadInfo.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="action-bar">
            <button class="action-btn" title="Reply" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">💬</button>
            <button class="action-btn" title="React" @onclick="ToggleEmojiPicker">😀</button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button class="emoji-option" @onclick="() => PickEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadInfo { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 6px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.92rem;
    line-height: 1.45;
    color: #333;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #e0e0e0;
    border-radius: 12px;
    font-size: 0.8rem;
    background: #f8f8f8;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background-color: #e8f0fe;
    border-color: #a8c7fa;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #4a90d9;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    padding: 2px;
}

.action-btn {
    border: none;
    background: transparent;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    padding: 6px;
    margin-top: 4px;
    width: fit-content;
}

.emoji-option {
    border: none;
    background: transparent;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1.2rem;
    line-height: 1;
}

.emoji-option:hover {
    background-color: #f0f0f0;
}

@using sv_e28233553a9341ab851b6ec0a2969985.Services

<nav class="channel-sidebar">
    <h2 class="sidebar-title">Channels</h2>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnClick="() => OnChannelSelected.InvokeAsync(channel)" />
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2f33;
    color: #fff;
    overflow: hidden;
}

.sidebar-title {
    padding: 16px;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
}

@using sv_e28233553a9341ab851b6ec0a2969985.Services

<aside class="thread-panel">
    <div class="thread-header">
        <h3 class="thread-title">Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="root-message-quote">
            <span class="quote-author">@RootMessage.Author</span>
            <p class="quote-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet.</p>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <MessageItem Message="reply" />
                }
            }
        </div>

        <MessageInput Placeholder="Reply..."
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</aside>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-title {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    border: none;
    background: transparent;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
