arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
}

@page "/chat"
@layout sv_e28233553a9341ab851b6ec0a2969985.Components.Layout.ChatLayout
@rendermode InteractiveServer
@using sv_e28233553a9341ab851b6ec0a2969985.Services
@using sv_e28233553a9341ab851b6ec0a2969985.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-panel">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannel?.Id"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-panel @(isThreadOpen ? "with-thread" : "")">
        @if (selectedChannel is not null)
        {
            <div class="channel-header">
                <h2 class="channel-name"># @selectedChannel.Name</h2>
                <span class="channel-desc">@selectedChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages...</div>
                }
                @foreach (var msg in messages)
                {
                    @if (msg.ReplyToId is null)
                    {
                        <MessageItem Message="msg"
                                     ThreadInfo="GetThreadInfo(msg.Id)"
                                     OnOpenThread="OpenThread"
                                     OnReact="HandleReaction" />
                    }
                }
            </div>

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")"
                          ButtonText="Send"
                          OnSubmit="SendMessage" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private bool isLoadingMore;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
        hasMoreMessages = true;

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh unread count locally
        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        var allReplies = await ChatService.GetThreadAsync(rootMessageId);
        // GetThreadAsync returns root + replies; filter to just replies
        threadReplies = allReplies.Where(m => m.Id != rootMessageId).ToList();
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (selectedChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task HandleScroll()
    {
        // Pagination is triggered from JS scroll events; here we provide the method
        // In a production app, use JS interop to detect scrollTop === 0
        // For this implementation, we provide a LoadMore method callable via scroll detection
    }

    internal async Task LoadOlderMessages()
    {
        if (!hasMoreMessages || isLoadingMore || selectedChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);

        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private ThreadSummary? GetThreadInfo(int messageId) =>
        threadSummaries.GetValueOrDefault(messageId);
}

