        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private async Task HandleScroll()
    {
        // Pagination is triggered from JS scroll events; here we provide the method
        // In a production app, use JS interop to detect scrollTop === 0
        // For this implementation, we provide a LoadMore method callable via scroll detection
    }

    internal async Task LoadOlderMessages()
    {
        if (!hasMoreMessages || isLoadingMore || selectedChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);

        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private ThreadSummary? GetThreadInfo(int messageId) =>
        threadSummaries.GetValueOrDefault(messageId);
}

