+        messages.InsertRange(0, older);
+
+        isLoadingMore = false;
+    }
+
+    private void BuildThreadSummaries()
+    {
+        threadSummaries.Clear();
+        var replies = messages.Where(m => m.ReplyToId is not null).ToList();
+        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
+        {
+            threadSummaries[group.Key] = new ThreadSummary(
+                group.Key,
+                group.Count(),
+                group.Max(m => m.SentAt));
+        }
+    }
+
+    private ThreadSummary? GetThreadInfo(int messageId) =>
+        threadSummaries.GetValueOrDefault(messageId);
+}
+

toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
}

.sidebar-panel {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.main-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.main-panel.with-thread {
    /* When thread is open, main panel shrinks */
}

.thread-panel-container {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.channel-name {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a1a;
}

.channel-desc {
    font-size: 0.83rem;
    color: #888;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 0.85rem;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

